// src/components/StyleEditor/StyleEditor.jsx
import React, { useState, useEffect, useCallback } from 'react';
import { styleService } from '../../services/styleService';
import './StyleEditor.css';

const StyleEditor = ({ conferenceId, onSave, onClose, embedded = false }) => {
    const [styles, setStyles] = useState(null);
    const [loading, setLoading] = useState(true); // Меняем на true
    const [activeTab, setActiveTab] = useState('general');
    const [saving, setSaving] = useState(false);
    
    console.log('StyleEditor mounted, conferenceId:', conferenceId);
    
    const loadStyles = useCallback(async () => {
        console.log('Загрузка стилей...');
        setLoading(true);
        try {
            const loadedStyles = await styleService.getConferenceStyles(conferenceId);
            console.log('Стили загружены:', loadedStyles);
            setStyles(loadedStyles);
        } catch (error) {
            console.error('Ошибка загрузки стилей:', error);
        } finally {
            setLoading(false);
        }
    }, [conferenceId]);
    
    useEffect(() => {
        if (conferenceId) {
            loadStyles();
        } else {
            console.warn('conferenceId не передан!');
            setLoading(false);
        }
    }, [conferenceId, loadStyles]);
    
    const handleStyleChange = (key, value) => {
        setStyles(prev => ({
            ...prev,
            [key]: value
        }));
    };
    
    const handleSave = async () => {
        setSaving(true);
        try {
            const token = localStorage.getItem('token');
            await styleService.saveConferenceStyles(conferenceId, styles, token);
            alert('Стили успешно сохранены!');
            if (onSave) onSave();
        } catch (error) {
            console.error('Ошибка сохранения:', error);
            alert('Ошибка при сохранении стилей: ' + error.message);
        } finally {
            setSaving(false);
        }
    };
    
    // Показываем загрузку
    if (loading) {
        return (
            <div style={{
                position: 'fixed',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                background: 'rgba(0,0,0,0.5)',
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
                zIndex: 9999
            }}>
                <div style={{
                    background: 'white',
                    padding: '30px',
                    borderRadius: '10px',
                    textAlign: 'center'
                }}>
                    <div>⏳ Загрузка стилей...</div>
                </div>
            </div>
        );
    }
    
    // Если стили не загрузились, показываем форму по умолчанию
    const defaultStyles = {
        page_background: '#ffffff',
        container_padding: 40,
        font_family: 'Arial, sans-serif',
        title_font_size: 32,
        title_font_weight: '600',
        title_color: '#f39c12',
        title_text_align: 'center',
        title_margin_bottom: 30,
        authors_font_size: 16,
        authors_font_weight: '400',
        authors_color: '#e67e22',
        authors_text_align: 'center',
        authors_margin_bottom: 20,
        abstract_font_size: 14,
        abstract_font_weight: '400',
        abstract_color: '#333333',
        abstract_line_height: 1.6,
        abstract_margin_bottom: 30,
        text_font_size: 14,
        text_line_height: 1.6,
        text_color: '#333333',
        text_margin_bottom: 15,
        table_border_color: '#000000',
        table_header_bg: '#f8f9fa',
        table_cell_padding: 8
    };
    
    const currentStyles = styles || defaultStyles;
    
    // Всегда показываем редактор, даже если стили не загружены
    const editorContent = (
        <div className="style-editor-embedded">
            <div className="style-editor-header-embedded">
                <h2>Настройка внешнего вида конференции</h2>
                <p>Настройте стили для статей, которые будут подаваться на эту конференцию</p>
            </div>
            
            <div className="style-editor-tabs">
                <button className={activeTab === 'general' ? 'active' : ''} 
                        onClick={() => setActiveTab('general')}>
                    Общие
                </button>
                <button className={activeTab === 'title' ? 'active' : ''} 
                        onClick={() => setActiveTab('title')}>
                    Заголовок
                </button>
                <button className={activeTab === 'authors' ? 'active' : ''} 
                        onClick={() => setActiveTab('authors')}>
                    Авторы
                </button>
                <button className={activeTab === 'abstract' ? 'active' : ''} 
                        onClick={() => setActiveTab('abstract')}>
                    Аннотация
                </button>
                <button className={activeTab === 'text' ? 'active' : ''} 
                        onClick={() => setActiveTab('text')}>
                    Текст
                </button>
                <button className={activeTab === 'tables' ? 'active' : ''} 
                        onClick={() => setActiveTab('tables')}>
                    Таблицы
                </button>
            </div>
            
            <div className="style-editor-content">
                {activeTab === 'general' && (
                    <div className="style-group">
                        <div className="style-field">
                            <label>Цвет фона страницы</label>
                            <input
                                type="color"
                                value={currentStyles.page_background}
                                onChange={(e) => handleStyleChange('page_background', e.target.value)}
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Отступ контейнера (px)</label>
                            <input
                                type="number"
                                value={currentStyles.container_padding}
                                onChange={(e) => handleStyleChange('container_padding', parseInt(e.target.value))}
                                min="0"
                                max="100"
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Основной шрифт</label>
                            <select
                                value={currentStyles.font_family}
                                onChange={(e) => handleStyleChange('font_family', e.target.value)}
                            >
                                <option value="Arial, sans-serif">Arial</option>
                                <option value="Times New Roman, serif">Times New Roman</option>
                                <option value="Futura PT, sans-serif">Futura PT</option>
                                <option value="Georgia, serif">Georgia</option>
                                <option value="Verdana, sans-serif">Verdana</option>
                            </select>
                        </div>
                    </div>
                )}
                
                {activeTab === 'title' && (
                    <div className="style-group">
                        <div className="style-field">
                            <label>Размер шрифта заголовка (px)</label>
                            <input
                                type="number"
                                value={currentStyles.title_font_size}
                                onChange={(e) => handleStyleChange('title_font_size', parseInt(e.target.value))}
                                min="12"
                                max="72"
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Насыщенность шрифта</label>
                            <select
                                value={currentStyles.title_font_weight}
                                onChange={(e) => handleStyleChange('title_font_weight', e.target.value)}
                            >
                                <option value="400">Обычный (400)</option>
                                <option value="500">Средний (500)</option>
                                <option value="600">Полужирный (600)</option>
                                <option value="700">Жирный (700)</option>
                            </select>
                        </div>
                        
                        <div className="style-field">
                            <label>Цвет заголовка</label>
                            <input
                                type="color"
                                value={currentStyles.title_color}
                                onChange={(e) => handleStyleChange('title_color', e.target.value)}
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Выравнивание</label>
                            <select
                                value={currentStyles.title_text_align}
                                onChange={(e) => handleStyleChange('title_text_align', e.target.value)}
                            >
                                <option value="left">По левому краю</option>
                                <option value="center">По центру</option>
                                <option value="right">По правому краю</option>
                            </select>
                        </div>
                        
                        <div className="style-field">
                            <label>Отступ снизу (px)</label>
                            <input
                                type="number"
                                value={currentStyles.title_margin_bottom}
                                onChange={(e) => handleStyleChange('title_margin_bottom', parseInt(e.target.value))}
                                min="0"
                                max="100"
                            />
                        </div>
                    </div>
                )}
                
                {activeTab === 'authors' && (
                    <div className="style-group">
                        <div className="style-field">
                            <label>Размер шрифта авторов (px)</label>
                            <input
                                type="number"
                                value={currentStyles.authors_font_size}
                                onChange={(e) => handleStyleChange('authors_font_size', parseInt(e.target.value))}
                                min="10"
                                max="48"
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Цвет авторов</label>
                            <input
                                type="color"
                                value={currentStyles.authors_color}
                                onChange={(e) => handleStyleChange('authors_color', e.target.value)}
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Выравнивание</label>
                            <select
                                value={currentStyles.authors_text_align}
                                onChange={(e) => handleStyleChange('authors_text_align', e.target.value)}
                            >
                                <option value="left">По левому краю</option>
                                <option value="center">По центру</option>
                                <option value="right">По правому краю</option>
                            </select>
                        </div>
                        
                        <div className="style-field">
                            <label>Отступ снизу (px)</label>
                            <input
                                type="number"
                                value={currentStyles.authors_margin_bottom}
                                onChange={(e) => handleStyleChange('authors_margin_bottom', parseInt(e.target.value))}
                                min="0"
                                max="100"
                            />
                        </div>
                    </div>
                )}
                
                {activeTab === 'abstract' && (
                    <div className="style-group">
                        <div className="style-field">
                            <label>Размер шрифта аннотации (px)</label>
                            <input
                                type="number"
                                value={currentStyles.abstract_font_size}
                                onChange={(e) => handleStyleChange('abstract_font_size', parseInt(e.target.value))}
                                min="10"
                                max="24"
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Межстрочный интервал</label>
                            <input
                                type="number"
                                step="0.1"
                                value={currentStyles.abstract_line_height}
                                onChange={(e) => handleStyleChange('abstract_line_height', parseFloat(e.target.value))}
                                min="1"
                                max="2.5"
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Цвет текста</label>
                            <input
                                type="color"
                                value={currentStyles.abstract_color}
                                onChange={(e) => handleStyleChange('abstract_color', e.target.value)}
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Отступ снизу (px)</label>
                            <input
                                type="number"
                                value={currentStyles.abstract_margin_bottom}
                                onChange={(e) => handleStyleChange('abstract_margin_bottom', parseInt(e.target.value))}
                                min="0"
                                max="100"
                            />
                        </div>
                    </div>
                )}
                
                {activeTab === 'text' && (
                    <div className="style-group">
                        <div className="style-field">
                            <label>Размер основного текста (px)</label>
                            <input
                                type="number"
                                value={currentStyles.text_font_size}
                                onChange={(e) => handleStyleChange('text_font_size', parseInt(e.target.value))}
                                min="10"
                                max="24"
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Межстрочный интервал</label>
                            <input
                                type="number"
                                step="0.1"
                                value={currentStyles.text_line_height}
                                onChange={(e) => handleStyleChange('text_line_height', parseFloat(e.target.value))}
                                min="1"
                                max="2.5"
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Цвет текста</label>
                            <input
                                type="color"
                                value={currentStyles.text_color}
                                onChange={(e) => handleStyleChange('text_color', e.target.value)}
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Отступ снизу (px)</label>
                            <input
                                type="number"
                                value={currentStyles.text_margin_bottom}
                                onChange={(e) => handleStyleChange('text_margin_bottom', parseInt(e.target.value))}
                                min="0"
                                max="50"
                            />
                        </div>
                    </div>
                )}
                
                {activeTab === 'tables' && (
                    <div className="style-group">
                        <div className="style-field">
                            <label>Цвет границ таблицы</label>
                            <input
                                type="color"
                                value={currentStyles.table_border_color}
                                onChange={(e) => handleStyleChange('table_border_color', e.target.value)}
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Цвет фона заголовка таблицы</label>
                            <input
                                type="color"
                                value={currentStyles.table_header_bg}
                                onChange={(e) => handleStyleChange('table_header_bg', e.target.value)}
                            />
                        </div>
                        
                        <div className="style-field">
                            <label>Отступ в ячейках (px)</label>
                            <input
                                type="number"
                                value={currentStyles.table_cell_padding}
                                onChange={(e) => handleStyleChange('table_cell_padding', parseInt(e.target.value))}
                                min="2"
                                max="20"
                            />
                        </div>
                    </div>
                )}
            </div>
            
            <div className="style-editor-actions">
                <button type="button" onClick={onClose} className="btn-secondary">
                    ← Назад к редактированию
                </button>
                <button type="button" onClick={handleSave} disabled={saving} className="btn-primary">
                    {saving ? 'Сохранение...' : 'Сохранить стили и завершить'}
                </button>
            </div>
        </div>
    );
    
    return editorContent;
};

export default StyleEditor;
